public class Report {
  public string Title { get; }
  public string Body { get; }
  public string Footer { get; }

  public Report(string title, string body, string footer) {
    Title = title;
    Body = body;
    Footer = footer;
  }
}

public class ReportBuilder {
  private string _title = "";
  private string _body = "";
  private string _footer = "";

  public ReportBuilder WithTitle(string title) { _title = title; return this; }
  public ReportBuilder WithBody(string body) { _body = body; return this; }
  public ReportBuilder WithFooter(string footer) { _footer = footer; return this; }

  public Report Build() {
    if (string.IsNullOrWhiteSpace(_title)) throw new InvalidOperationException("Title is required");
    return new Report(_title, _body, _footer);
  }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Build_CreatesReportWithConfiguredValues() {
  var report = new ReportBuilder()
    .WithTitle("Weekly")
    .WithBody("Body")
    .WithFooter("Footer")
    .Build();

  Assert.AreEqual("Weekly", report.Title);
  Assert.AreEqual("Body", report.Body);
  Assert.AreEqual("Footer", report.Footer);
}

[TestMethod]
[ExpectedException(typeof(InvalidOperationException))]
public void Build_ThrowsWhenTitleIsMissing() {
  _ = new ReportBuilder().WithBody("Body").Build();
}
